import streamlit as st
import random
import time

st.set_page_config(page_title="MindGrid", layout="centered", page_icon="✖")

LOGO_B64 = ""

# ── Game Logic ────────────────────────────────────────────────────────────────

WINS = [(0,1,2),(3,4,5),(6,7,8),(0,3,6),(1,4,7),(2,5,8),(0,4,8),(2,4,6)]

def check_winner(board):
    for a,b,c in WINS:
        if board[a] and board[a] == board[b] == board[c]:
            return board[a], [a,b,c]
    if all(board):
        return "draw", []
    return None, []

def minimax(board, maximizing, ai, human, depth=0):
    w, _ = check_winner(board)
    if w == ai:     return 10 - depth
    if w == human:  return depth - 10
    if w == "draw": return 0
    empty = [i for i in range(9) if not board[i]]
    if maximizing:
        best = -99
        for i in empty:
            board[i] = ai
            best = max(best, minimax(board, False, ai, human, depth+1))
            board[i] = ""
        return best
    else:
        best = 99
        for i in empty:
            board[i] = human
            best = min(best, minimax(board, True, ai, human, depth+1))
            board[i] = ""
        return best

def ai_move(board, ai, human, difficulty):
    empty = [i for i in range(9) if not board[i]]
    if not empty: return None
    if difficulty == "Easy":
        # 75% random — feels beatable
        if random.random() < 0.75:
            return random.choice(empty)
        # 25%: at least block an obvious win
        for i in empty:
            board[i] = ai
            w, _ = check_winner(board)
            board[i] = ""
            if w == ai: return i
        return random.choice(empty)
    # Hard — full minimax
    best_score, best_move = -99, empty[0]
    for i in empty:
        board[i] = ai
        s = minimax(board, False, ai, human)
        board[i] = ""
        if s > best_score:
            best_score, best_move = s, i
    return best_move

# ── Session State ─────────────────────────────────────────────────────────────

def _init():
    defaults = {
        "board": [""]*9, "player": "X", "ai": "O",
        "turn": "player", "over": False, "winner": None,
        "win_cells": [], "score": {"player":0,"ai":0,"draws":0},
        "difficulty": "Hard", "started": False, "log": []
    }
    for k, v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v
_init()

def do_ai_move():
    if st.session_state.over: return
    b = st.session_state.board
    m = ai_move(b[:], st.session_state.ai, st.session_state.player,
                st.session_state.difficulty)
    if m is None: return
    b[m] = st.session_state.ai
    st.session_state.log.append(f"AI → C{m+1}")
    w, cells = check_winner(b)
    if w:
        st.session_state.over = True
        st.session_state.winner = w
        st.session_state.win_cells = cells
        if w == st.session_state.ai:
            st.session_state.score["ai"] += 1
        elif w == "draw":
            st.session_state.score["draws"] += 1
    else:
        st.session_state.turn = "player"

def new_round():
    st.session_state.board = [""]*9
    st.session_state.over = False
    st.session_state.winner = None
    st.session_state.win_cells = []
    st.session_state.log = []
    st.session_state.turn = "player"
    if st.session_state.player == "O":
        st.session_state.turn = "ai"
        do_ai_move()
        st.session_state.turn = "player"

