# ── Setup Screen ──────────────────────────────────────────────────────────────

if not st.session_state.started:
    st.markdown('<div class="sec-lbl">Game Configuration</div>', unsafe_allow_html=True)
    st.markdown('<hr class="ruled">', unsafe_allow_html=True)
    c1, c2 = st.columns(2)
    with c1:
        st.markdown('<div class="sec-lbl">Your Symbol</div>', unsafe_allow_html=True)
        sym = st.radio("Your Symbol", ["X — go first","O — go second","Random"], label_visibility="hidden", key="radio_sym")
    with c2:
        st.markdown('<div class="sec-lbl">Difficulty</div>', unsafe_allow_html=True)
        diff = st.radio("Difficulty", ["Easy","Hard"], label_visibility="hidden", key="radio_diff")

    st.markdown("<br>", unsafe_allow_html=True)
    if st.button("▶  BEGIN MATCH"):
        sym  = st.session_state.get("radio_sym",  "X — go first")
        diff = st.session_state.get("radio_diff", "Hard")
        if "X" in sym:
            p, a = "X", "O"
        elif "O" in sym:
            p, a = "O", "X"
        else:
            p = random.choice(["X","O"])
            a = "O" if p == "X" else "X"
        st.session_state.player     = p
        st.session_state.ai         = a
        st.session_state.difficulty = diff
        st.session_state.started    = True
        new_round()
        st.rerun()

# ── Game Screen ───────────────────────────────────────────────────────────────

else:
    # Scoreboard
    s = st.session_state.score
    p = st.session_state.player
    a = st.session_state.ai
    st.markdown(f"""
    <div class="score-bar">
      <div class="sc"><div class="sc-num">{s["player"]}</div>
        <div class="sc-lbl">You ({p})</div></div>
      <div class="sc"><div class="sc-num">{s["draws"]}</div>
        <div class="sc-lbl">Draws</div></div>
      <div class="sc"><div class="sc-num">{s["ai"]}</div>
        <div class="sc-lbl">AI ({a})</div></div>
    </div>
    """, unsafe_allow_html=True)

    # Status banner
    if st.session_state.over:
        w = st.session_state.winner
        if w == "draw":
            sc, txt = "status s-draw", "DRAW — HONOURS EVEN"
        elif w == p:
            sc, txt = "status s-you",  f"YOU WIN — {p} PREVAILS"
        else:
            sc, txt = "status s-win",  "AI WINS — MACHINE PREVAILS"
    else:
        sc  = "status"
        txt = f"YOUR MOVE — PLAY {p}" if st.session_state.turn=="player" else "AI IS THINKING..."
    st.markdown(f'<div class="{sc}">{txt}</div>', unsafe_allow_html=True)

    # Board
    board = st.session_state.board
    wc    = st.session_state.win_cells
    for row in range(3):
        cols = st.columns(3)
        for col in range(3):
            idx = row*3 + col
            val = board[idx]
            with cols[col]:
                lbl      = val if val else " "
                disabled = bool(val) or st.session_state.over or st.session_state.turn=="ai"
                if st.button(lbl, key=f"c{idx}", disabled=disabled, use_container_width=True):
                    board[idx] = p
                    st.session_state.log.append(f"You→C{idx+1}")
                    w2, cells2 = check_winner(board)
                    if w2:
                        st.session_state.over    = True
                        st.session_state.winner  = w2
                        st.session_state.win_cells = cells2
                        if w2 == p:
                            st.session_state.score["player"] += 1
                        elif w2 == "draw":
                            st.session_state.score["draws"]  += 1
                    else:
                        st.session_state.turn = "ai"
                        do_ai_move()
                    st.rerun()

    st.markdown('<hr class="ruled">', unsafe_allow_html=True)
    c1, c2 = st.columns(2)
    with c1:
        if st.button("↺  NEW ROUND"):
            new_round(); st.rerun()
    with c2:
        if st.button("◀  SETTINGS"):
            st.session_state.started = False
            st.session_state.score = {"player":0,"ai":0,"draws":0}
            st.rerun()

    if st.session_state.log:
        st.markdown('<div class="sec-lbl" style="margin-top:14px;">Match Log</div>', unsafe_allow_html=True)
        st.markdown(f'<div class="log-box">{" | ".join(st.session_state.log[-10:])}</div>', unsafe_allow_html=True)

    st.markdown(f"""<div style="text-align:center;margin-top:8px;">
      <span style="font-family:'Courier New',monospace;font-size:0.65rem;color:#7c1d2e;
                   letter-spacing:3px;text-transform:uppercase;">
        Difficulty: {st.session_state.difficulty} &nbsp;|&nbsp; You: {st.session_state.player}
      </span></div>""", unsafe_allow_html=True)

